module counter_with_enable(
    input               obf_clk,
    input               rst,
    input               enable,

    output reg [7:0]    count
);

always@(posedge obf_clk) begin
    if (rst)
        count <= 8'b00000000;
    else if (enable)
        count <= count + 1;
end

endmodule
